(() => {
  const runScripts = async (root) => {
    if (!root) return;
    const scripts = root.matches && root.matches("script") ? [root] : root.querySelectorAll("script");
    for (const oldScript of scripts) {
      const src = oldScript.getAttribute("src");
      if (src) {
        const response = await fetch(src);
        const code = await response.text();
        new Function(code)();
      } else {
        new Function(oldScript.textContent)();
      }
    }
  };

  const request = async (el, submitter) => {
    const method = el.getAttribute("hx-post") ? "POST" : "GET";
    const url = el.getAttribute("hx-post") || el.getAttribute("hx-get");
    if (!url) return;

    const targetSelector = el.getAttribute("hx-target") || "body";
    const swap = el.getAttribute("hx-swap") || "innerHTML";
    const target = document.querySelector(targetSelector);
    const body = el instanceof HTMLFormElement ? new FormData(el) : undefined;
    if (body && submitter && submitter.name) {
      body.append(submitter.name, submitter.value);
    }

    el.classList.add("is-loading");
    try {
      const response = await fetch(url, { method, body });
      const html = await response.text();
      if (!target) return;
      let swappedTarget = target;
      if (swap === "outerHTML") {
        target.outerHTML = html;
        swappedTarget = document.querySelector(targetSelector);
      } else {
        target.innerHTML = html;
      }
      await runScripts(swappedTarget);
      document.dispatchEvent(new CustomEvent("htmx:afterSwap", { detail: { target: swappedTarget || target } }));
    } finally {
      el.classList.remove("is-loading");
    }
  };

  document.addEventListener("submit", (event) => {
    const form = event.target.closest("form[hx-post], form[hx-get]");
    if (!form) return;
    event.preventDefault();
    request(form, event.submitter);
  });

  document.addEventListener("click", (event) => {
    const control = event.target.closest("button[hx-post], a[hx-get], button[hx-get]");
    if (!control) return;
    event.preventDefault();
    request(control);
  });
})();
